    url: null, img: "https://imgproxy.ra.co/_/quality:66/aHR0cHM6Ly9zdGF0aWMucmEuY28vaW1hZ2VzL25ld3MvMjAyNi9rYWxhZmVzdGl2YWwuanBlZw==",
